#!/bin/sh
set -e

echo "=========================================="
echo "Installing South African Real Estate CRM"
echo "=========================================="

cd /app/nocobase

psql "$DATABASE_URL" << 'PSQL' 2>/dev/null || true

-- Create CRM tables
CREATE TABLE IF NOT EXISTS "crm_leads" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "first_name" varchar(255),
  "last_name" varchar(255),
  "full_name" varchar(255),
  "email" varchar(255),
  "phone" varchar(255),
  "mobile" varchar(255),
  "company" varchar(255),
  "status" varchar(255) DEFAULT 'new',
  "source" varchar(255),
  "budget_min" decimal,
  "budget_max" decimal,
  "preferred_location" varchar(255),
  "property_type" varchar(255),
  "bedrooms_required" integer,
  "timeline" varchar(255),
  "rating" integer,
  "rsa_id" varchar(255),
  "tax_number" varchar(255),
  "fica_status" varchar(50) DEFAULT 'pending',
  "notes" text,
  "created_at" timestamptz DEFAULT NOW(),
  "updated_at" timestamptz DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS "crm_properties" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "title" varchar(255),
  "address" varchar(255),
  "suburb" varchar(255),
  "city" varchar(255) DEFAULT 'Johannesburg',
  "province" varchar(255) DEFAULT 'Gauteng',
  "postal_code" varchar(255),
  "property_type" varchar(255),
  "status" varchar(255) DEFAULT 'available',
  "price" decimal,
  "bedrooms" integer,
  "bathrooms" integer,
  "garages" integer,
  "erf_size" integer,
  "floor_size" integer,
  "pool" boolean DEFAULT false,
  "garden" boolean DEFAULT false,
  "security" boolean DEFAULT false,
  "description" text,
  "features" jsonb,
  "listing_date" timestamptz,
  "created_at" timestamptz DEFAULT NOW(),
  "updated_at" timestamptz DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS "crm_deals" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "title" varchar(255),
  "lead_id" bigint,
  "property_id" bigint,
  "stage" varchar(255) DEFAULT 'qualification',
  "value" decimal,
  "commission_rate" decimal DEFAULT 3.0,
  "commission_amount" decimal,
  "fica_checklist" jsonb,
  "fica_status" varchar(50) DEFAULT 'pending',
  "notes" text,
  "expected_close_date" timestamptz,
  "actual_close_date" timestamptz,
  "created_at" timestamptz DEFAULT NOW(),
  "updated_at" timestamptz DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS "crm_contacts" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "first_name" varchar(255),
  "last_name" varchar(255),
  "full_name" varchar(255),
  "email" varchar(255),
  "phone" varchar(255),
  "mobile" varchar(255),
  "rsa_id" varchar(255),
  "address" varchar(255),
  "suburb" varchar(255),
  "city" varchar(255),
  "province" varchar(255) DEFAULT 'Gauteng',
  "postal_code" varchar(255),
  "fica_status" varchar(50) DEFAULT 'pending',
  "notes" text,
  "created_at" timestamptz DEFAULT NOW(),
  "updated_at" timestamptz DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS "crm_suburbs" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "name" varchar(255),
  "city" varchar(255) DEFAULT 'Johannesburg',
  "province" varchar(255) DEFAULT 'Gauteng',
  "latitude" decimal,
  "longitude" decimal,
  "average_price" decimal,
  "median_price" decimal,
  "total_listings" integer DEFAULT 0,
  "created_at" timestamptz DEFAULT NOW(),
  "updated_at" timestamptz DEFAULT NOW()
);

-- Insert sample suburbs
INSERT INTO "crm_suburbs" ("name", "city", "province", "latitude", "longitude", "average_price", "median_price", "total_listings") VALUES
