INSERT INTO "collection_fields" ("collectionName", "name", "type", "interface", "title", "dataType", "uiSchema", "defaultValue", "creator", "createdAt", "updatedAt") VALUES
('crm_properties', 'title', 'string', 'input', 'Title', 'VARCHAR', '{"en-US":{"title":"Title"}}', null, 'system', NOW(), NOW()),
('crm_properties', 'address', 'string', 'input', 'Address', 'VARCHAR', '{"en-US":{"title":"Address"}}', null, 'system', NOW(), NOW()),
('crm_properties', 'price', 'decimal', 'number', 'Price (ZAR)', 'DECIMAL', '{"en-US":{"title":"Price (ZAR)"}}', null, 'system', NOW(), NOW()),
('crm_properties', 'status', 'string', 'select', 'Status', 'VARCHAR', '{"en-US":{"title":"Status","enum":[{"label":"Available","value":"available"},{"label":"Sold","value":"sold"}]}}', 'available', 'system', NOW(), NOW())
ON CONFLICT DO NOTHING;

-- Add CRM menu item to sidebar
DELETE FROM "ui_schemas" WHERE "id" = 9001;

INSERT INTO "ui_schemas" ("id", "uiSchema", "createdAt", "updatedAt") VALUES
(9001, '{"type":"void","version":"2.0","x-uid":"crm-menu","x-designer":{"placement":"sidebar"},"title":"CRM","name":"crm","icon":"ShopOutlined","children":[{"version":"2.0","x-uid":"crm-leads","x-designer":{"placement":"inline"},"type":"page","title":"Leads","icon":"UserOutlined","name":"crm_leads","path":"/crm/leads","children":[]},{"version":"2.0","x-uid":"crm-properties","x-designer":{"placement":"inline"},"type":"page","title":"Properties","icon":"HomeOutlined","name":"crm_properties","path":"/crm/properties","children":[]},{"version":"2.0","x-uid":"crm-deals","x-designer":{"placement":"inline"},"type":"page","title":"Deals","icon":"PercentageOutlined","name":"crm_deals","path":"/crm/deals","children":[]}]}', NOW(), NOW());

PSQL

echo "CRM installation complete!"
echo ""
echo "To view your CRM data:"
echo "1. Go to Settings > Data Source Manager > Main Database > Collections"
echo "2. You should see: Leads, Properties, Deals, Contacts, Suburbs"
echo "3. Click on any collection and configure the UI to add to sidebar"

exit 0
